grid:






































select 'init$GridReport$(this);' as message
return



    &XMLWhenReportLoading;
    &XMLWhenReportClosing;




      &JavascriptReportInit;
      /* <flatten type="Javascript"> */
function init$GridReport$(g) {changeHeader$GridReport(g, 'ma', 'ten', g._language, g._groupBy);}
function changeHeader$GridReport(g, c, n, l, e) {
  var i = g._getColumnOrder(c), fieldCode = g._fields[i - 1], j = g._getColumnOrder(n), fieldName = g._fields[j - 1], k = l == 'v' ? 0 : 1, n = parseInt(e);
  var a = [
    [['Tk đối ứng', 'Reference Account'], ['Tên tài khoản đối ứng', 'Reference Account Name']],
    [['Tài khoản', 'Account'], ['Tên tài khoản', 'Account Name']],
    [['Mã khách', 'Customer'], ['Tên khách hàng', 'Customer Name']],
    [['Vụ việc', 'Job'], ['Tên vụ việc', 'Job Name']],
    [['Sản phẩm', 'Product'], ['Tên sản phẩm', 'Product Name']],
    [['Bộ phận', 'Department'], ['Tên bộ phận', 'Department Name']],
    [['Đơn vị', 'Unit'], ['Tên đơn vị', 'Unit Name']]
  ];
  fieldCode.HeaderText = a[n][0][k];
  fieldName.HeaderText = a[n][1][k];

  g._externalHeaderFields = [];
  Array.add(g._externalHeaderFields, {Index: fieldCode.Index, Header: fieldCode.HeaderText});
  Array.add(g._externalHeaderFields, {Index: fieldName.Index, Header: fieldName.HeaderText});
}
/* </flatten> */



  &XMLStandardReportToolbar;
